$(async () => {
  const MIN_LENGTH = 5;    // 最小有效长度
  const RETRY_DELAY = 500; // 重试延迟(ms)

  let enabled = true;
  let retryCount = 0;

  // 生成结束后检查
  eventOn(tavern_events.GENERATION_ENDED, () => {
    if (!enabled) return;

    setTimeout(() => {
      try {
        const lastMsg = getChatMessages(-1)[0];
        if (!lastMsg || lastMsg.role !== 'assistant') return;

        const len = (lastMsg.message || '').trim().length;

        if (len < MIN_LENGTH) {
          retryCount++;
          toastr.info(`过短(${len}字)，第${retryCount}次重试...`, '重试');
          $('#option_regenerate').click();
        } else {
          if (retryCount > 0) toastr.success(`成功！重试${retryCount}次`, '✅');
          retryCount = 0;
        }
      } catch (e) {}
    }, RETRY_DELAY);
  });

  // 停止
  eventOn(getButtonEvent('停止'), () => {
    enabled = false;
    toastr.warning(`已停止，重试${retryCount}次`, '停止');
    retryCount = 0;
  });

  // 开启
  eventOn(getButtonEvent('开启'), () => {
    enabled = true;
    retryCount = 0;
    toastr.success('已开启', '✅');
  });

  toastr.success('自动重试已启用', '✅');
});
